SELECT DISTINCT A.BoardID BoardID, CASE #primary# WHEN '1' THEN A.boardname ELSE CASE WHEN (A.boardname2 = '' OR A.boardname2 IS NULL) THEN A.boardname ELSE A.boardname2 END END BoardName, A.TreeViewOrder TreeViewOrder , A.BoardColor BoardColor , A.Gubun , B.BOARDGROUPACL BOARDGROUPACL FROM TBL_Board_BoardInfo A JOIN (SELECT C.BoardID , C.AccessID , C.Access_ , C.BoardGroupACL , C.tenant_id FROM TBL_Board_BoardManage C LEFT JOIN TBL_Board_BoardInfo D ON C.TENANT_ID = D.TENANT_ID AND C.BoardID = D.BoardID WHERE C.TENANT_ID = #tenantID# AND C.Access_ = 1 AND C.BoardID <> #excludeBoardID# AND ( C.AccessID = #userID# ) AND D.ParentBoardID = #rootBoardID#
AND C.BoardGroupACL = 'Y'
) B ON A.TENANT_ID = B.TENANT_ID AND A.BoardID = B.BOARDID WHERE A.TENANT_ID = #tenantID# AND (A.companyid = #companyID# OR TRIM(A.COMPANYID) = '' OR A.COMPANYID IS NULL) ORDER BY A.TreeViewOrder ASC

